return $input.all().map(item => {
  const sentDateTime = item.json.sentDateTime;
  const lastCheckedRaw = $('Get last checked').first().json.allLastCheckedAt;

  // Try parsing lastChecked into a Date, guard against empty/invalid
  let lastChecked = null;
  if (lastCheckedRaw && !isNaN(Date.parse(lastCheckedRaw))) {
    lastChecked = new Date(lastCheckedRaw);
  }

  // Condition 1: sentDateTime is after or equal to lastChecked
  let cond1 = false;
  if (sentDateTime && lastChecked) {
    const sent = new Date(sentDateTime);
    cond1 = sent >= lastChecked;
  }

  // Condition 2: sender != first recipient
  const sender = item.json.sender?.emailAddress?.address;
  const recipient = item.json.toRecipients?.[0]?.emailAddress?.name;
  const cond2 = sender && recipient ? sender !== recipient : false;

  // Combine conditions
  const passesFilter = cond1 && cond2;

  return {
    json: {
      ...item.json,
      passesFilter
    }
  };
}).filter(item => item.json.passesFilter);

const ccObj = $('Filter by not self-sender and date').item.json.ccRecipients;
const bccObj = $('Filter by not self-sender and date').item.json.ccRecipients;

const ccList = ccObj.length > 0 ?
  ccObj.map((obj) => obj.emailAddress.address): [];

const bccList = bccObj.length > 0 ?
  bccObj.map((obj) => obj.emailAddress.address): [];

return {ccList: ccList, bccList: bccList};
